patch:
diff --git a/llvm/lib/Transforms/Utils/LoopPeel.cpp b/llvm/lib/Transforms/Utils/LoopPeel.cpp
index c5c637ab6e20..3982c13191b1 100644
--- a/llvm/lib/Transforms/Utils/LoopPeel.cpp
+++ b/llvm/lib/Transforms/Utils/LoopPeel.cpp
@@ -1213,8 +1213,15 @@ bool llvm::peelLoop(Loop *L, unsigned PeelCount, bool PeelLast, LoopInfo *LI,
   if (PeelLast) {
     // Now adjust users of the original exit values by replacing them with the
     // exit value from the peeled iteration.
-    for (const auto &[P, E] : ExitValues)
-      P->replaceAllUsesWith(VMap.lookup(E));
+    for (const auto &[P, E] : ExitValues) {
+      // VMap only contains entries for values that were cloned. If the
+      // incoming value E was not cloned (e.g., it is a constant or comes from
+      // outside the loop), fall back to replacing with E itself.
+      Value *NewV = VMap.lookup(E);
+      if (!NewV)
+        NewV = E;
+      P->replaceAllUsesWith(NewV);
+    }
     formLCSSA(*L, DT, LI, SE);
   } else {
     // Now adjust the phi nodes in the loop header to get their initial values

